--- PixelFont — pixel-exact tracker font + FRLG-style icon drop shadows.
---
--- Replaces TrackerPixelFont and ShadowedIcons. Generated by
--- generate_pixel_font.py from font_groups/*.png and icons.png.
---
--- Text glyphs: 0 = transparent, 1 = foreground, 2 = shadow. The shadow
--- color is computed at render time as half-brightness of the FG color,
--- so shadows follow whatever text color the caller specified.
---
--- Icon glyphs: 0 = transparent, 1..N = source color values (preserved
--- from Constants.PixelImages), N+1 = shadow. The Drawing.drawImageAsPixels
--- wrapper extends the colorList with shadowColor(colorList[1]) at index
--- N+1 so the base renderer paints those pixels.
---
--- Icon shadows are gated by the RogueMon Options toggle "Pixel-art icon
--- shadows" (default on). Text font is always active when this extension
--- is enabled.

local function PixelFont()
  local self = {}
  self.version = "2.0"
  self.name = "PixelFont"
  self.author = "drumstix576"
  self.description = "Pixel-exact tracker font and FRLG-style icon drop shadows."

  -- pristineOriginal: cache the first-seen value of a key so wrapper chains
  -- don't form across reloads. Prefers Roguemon.pristineOriginal (same
  -- _G.__roguemonCoreOriginals cache) for cross-extension consistency;
  -- falls back to direct cache when RogueMon isn't loaded.
  local function pristine(key, current)
    if _G.Roguemon and _G.Roguemon.pristineOriginal then
      return _G.Roguemon.pristineOriginal(key, current)
    end
    _G.__roguemonCoreOriginals = _G.__roguemonCoreOriginals or {}
    if _G.__roguemonCoreOriginals[key] == nil then
      _G.__roguemonCoreOriginals[key] = current
    end
    return _G.__roguemonCoreOriginals[key]
  end

  -- Shadow opacity. Effective formula is opaque per-channel:
  --   shadow = SHADOW_ALPHA * FG + (1 - SHADOW_ALPHA) * BG
  -- 0.5 ≈ 50% alpha (the visual default); raise toward 1.0 for a darker
  -- / stronger shadow, lower toward 0.0 to fade it into the BG. Stays
  -- opaque so two writes to the same pixel don't accumulate brighter.
  -- Edit this value to tune; no regen needed.
  local SHADOW_ALPHA = 0.25

  -- Header strip BG override. The move-table header (Moves N/M (LVL),
  -- PP, Pow, Acc) is drawn with bgHeaderShadow derived from
  -- Theme.COLORS["Main background"], but the visible strip can be a
  -- different color (custom theme paint, bleed-through from the game
  -- viewport, BizHawk's default GUI surface). If the visible BG doesn't
  -- match Main background, set this to the actual BG color (ARGB hex,
  -- 0xFFRRGGBB) so PixelFont mixes the shadow against the right BG and
  -- avoids a black halo over a tinted strip. nil = use Main background.
  local HEADER_BG = nil

  -- Per-channel weighted blend of FG and BG. bgColor=nil treats BG as
  -- black, the right answer over a dark panel and the legacy behavior.
  -- Passing the actual BG matters on tinted panels (e.g. the purple
  -- curses backdrop, the green FC-prize carousel) where a BG-less
  -- darkening reads as a near-black halo instead of a tonally
  -- consistent shadow.
  local function shadowColor(color, bgColor)
    local rgb = color % 0x01000000
    local r = math.floor(rgb / 0x10000)
    local g = math.floor((rgb % 0x10000) / 0x100)
    local b = rgb % 0x100
    local br, bg, bb = 0, 0, 0
    if bgColor then
      local brgb = bgColor % 0x01000000
      br = math.floor(brgb / 0x10000)
      bg = math.floor((brgb % 0x10000) / 0x100)
      bb = brgb % 0x100
    end
    local a = SHADOW_ALPHA
    local ia = 1 - a
    return 0xFF000000 + math.floor(r * a + br * ia + 0.5) * 0x10000
                      + math.floor(g * a + bg * ia + 0.5) * 0x100
                      + math.floor(b * a + bb * ia + 0.5)
  end

  -- Recover the caller's BG from the shadowcolor arg. The tracker derives
  -- shadowcolor as Utils.calcShadowColor(bg) = bg * 0.92, so dividing by
  -- 0.92 reverses the scale within rounding. Returns nil when no usable
  -- shadowcolor is supplied so shadowColor() falls back to FG/2.
  local function bgFromShadowColor(sc)
    if type(sc) ~= "number" then return nil end
    local rgb = sc % 0x01000000
    local r = math.floor(rgb / 0x10000)
    local g = math.floor((rgb % 0x10000) / 0x100)
    local b = rgb % 0x100
    local function unscale(v)
      local u = math.floor(v / 0.92 + 0.5)
      if u > 255 then u = 255 end
      return u
    end
    return 0xFF000000 + unscale(r) * 0x10000 + unscale(g) * 0x100 + unscale(b)
  end

  -- Build a shadowed copy of an icon table. Preserves non-numeric metadata
  -- (iconColors, getColors), extends both with shadow color at the shadow
  -- index, and replaces matrix rows. Tags so the drawImageAsPixels wrapper
  -- recognizes shadowed matrices.
  local function makeShadowed(orig, newRows, shadowValue)
    local out = {}
    if type(orig) == "table" then
      for k, v in pairs(orig) do
        if type(k) ~= "number" then out[k] = v end
      end
      if out.iconColors then
        local extended = {}
        for i, c in ipairs(out.iconColors) do extended[i] = c end
        extended[shadowValue] = shadowColor(out.iconColors[1])
        out.iconColors = extended
      end
      local origGetColors = out.getColors
      if type(origGetColors) == "function" then
        out.getColors = function(t)
          local list = origGetColors(t)
          local extended = {}
          for i, c in ipairs(list) do extended[i] = c end
          extended[shadowValue] = shadowColor(list[1])
          return extended
        end
      end
    end
    for i, row in ipairs(newRows) do out[i] = row end
    out._shadowed = true
    out._shadowValue = shadowValue
    return out
  end

  -- Read the RogueMon Options toggle (default on if RogueMon not loaded).
  local function iconShadowsEnabled()
    if _G.Roguemon and _G.Roguemon.OptionsManager
        and _G.Roguemon.OptionsManager.isEnabled then
      return _G.Roguemon.OptionsManager.isEnabled("Pixel-art icon shadows") ~= false
    end
    return true
  end

  -- Vertical leading: uniform across the font. BizHawk renders Franklin
  -- Gothic 9pt with baseline at y+9 (for drawText at y), and our padded
  -- matrices put the baseline at matrix row (FONT_ASCENT). We shift by
  -- (9 - FONT_ASCENT) so the two baselines coincide.
  local Y_LEADING = 0

  -- Inline-newline line gap. The native gui.drawText renders multi-line
  -- text using Franklin Gothic's natural line height (~9-10 px), tighter
  -- than the tracker's logical LINE_SPACING (11) used for stacking
  -- separate calls. Matching ~10 here keeps inline-wrapped text from
  -- overflowing the boxes the tracker sized for native font metrics
  -- (e.g. SegmentUI's wrapped carousel: line 1 at y=136, expects line 2
  -- to land at y=146 inside a box bordered at y=155).
  local NEWLINE_SPACING = 11 - 1

  -- Carousel "second-line" y-coercion. Vanilla TrackerScreen and
  -- SegmentUI both draw second-line carousel content at y=145 (computed
  -- as MARGIN+140 in SegmentUI's count text or as a literal in vanilla
  -- TrackerScreen.drawCarouselArea). With our taller font_height=11,
  -- those land 1 px above the FRLG-correct visual baseline; bump to 146
  -- so they vertically align with the wrapped second line at y+10.
  function self.drawText(x, y, text, color, shadowcolor, size, family, style)
    if Utils.isNilOrEmpty(text) then return end
    -- Fall back to the original renderer for anything that isn't the
    -- default body font (icons at size 5, headers at 15, etc.).
    if size ~= nil and size ~= 9 then
      return self.oldDrawText(x, y, text, color, shadowcolor, size, family, style)
    end
    if y == 145 then y = 146 end
    -- shadowcolor=false → caller explicitly opted out of the drop shadow
    -- (e.g. text drawn over the game viewport where a half-brightness
    -- echo of the FG reads as solid black against bright backgrounds).
    -- shadowcolor=number → tracker's calcShadowColor(BG); recover BG and
    -- mix with FG so the shadow tones match the panel (e.g. purple curses
    -- backdrop) rather than always darkening toward black.
    -- shadowcolor=nil → no BG hint; FG/2 (assumes black BG).
    local colorList
    if shadowcolor == false then
      colorList = { color }
    else
      colorList = { color, shadowColor(color, bgFromShadowColor(shadowcolor)) }
    end
    local xoffset = 0
    local yoffset = 0
    for c in tostring(text):gmatch(utf8.charpattern) do
      if c == "\n" then
        yoffset = yoffset + 1
        xoffset = 0
      else
        local glyph = self.Font[c]
        if glyph then
          -- Per-char left bearing matches the native font's metric, so
          -- the pixel glyph lands at the same x as gui.drawText would.
          local lb = self.FontLeftBearing[c] or 1
          Drawing.drawImageAsPixels(glyph,
            x + xoffset + lb,
            y + yoffset * NEWLINE_SPACING + Y_LEADING,
            colorList, nil)
        end
        -- Advance by the glyph's foreground width plus 1 px so the next
        -- glyph's leftmost FG sits one column past this glyph's rightmost
        -- FG. That one-column gap is where the right-edge shadow lives.
        xoffset = xoffset + (self.FontWidths[c] or 1) + 1
      end
    end
  end


