  -- Wrap Drawing.drawImageAsPixels so shadowed icon matrices get a shadow
  -- color injected into colorList at index = matrix._shadowValue. Pass
  -- shadowcolor=nil through so the base function's +1,+1 echo doesn't
  -- double up on our explicit shadow pixels. Non-shadowed matrices pass
  -- through unchanged.
  local _baseDrawImageAsPixels
  local _wrapInstalled = false

  local function shadowDrawImageAsPixels(matrix, x, y, color, sc)
    if matrix == nil or not matrix._shadowed then
      -- Non-shadowed icon: apply the same FG/BG midpoint formula text
      -- uses, so icons drawn over tinted panels (green FC-prize panel,
      -- purple curse panel) get a tonally consistent shadow instead of
      -- the darker calcShadowColor(BG) tint the caller passed in.
      if type(sc) == "number" then
        local fg
        if type(color) == "number" then
          fg = color
        elseif type(color) == "table" then
          fg = color[1]
        elseif matrix.iconColors then
          fg = matrix.iconColors[1]
        elseif type(matrix.getColors) == "function" then
          local list = matrix:getColors()
          fg = list and list[1]
        end
        if fg then
          sc = shadowColor(fg, bgFromShadowColor(sc))
        end
      end
      return _baseDrawImageAsPixels(matrix, x, y, color, sc)
    end
    local sv = matrix._shadowValue
    local colorList
    if not color then
      if type(matrix.getColors) == "function" then
        colorList = matrix:getColors()
      elseif matrix.iconColors then
        colorList = matrix.iconColors
      end
      colorList = colorList or { Theme.COLORS["Default text"] }
    elseif type(color) == "number" then
      colorList = { color }
    else
      colorList = color
    end
    if sc == false then
      -- Caller opted out of the drop shadow. Strip the shadow entry so the
      -- base renderer skips matrix pixels with value sv (nil colorList[sv]
      -- causes the per-pixel branch in Drawing.drawImageAsPixels to no-op).
      if colorList[sv] ~= nil then
        local truncated = {}
        for i = 1, sv - 1 do truncated[i] = colorList[i] end
        colorList = truncated
      end
    else
      -- Always recompute the shadow at draw time so we can honor the BG
      -- hint encoded in `sc` (the same calcShadowColor(BG) value the
      -- caller would pass to Drawing.drawText). Mixing FG with BG keeps
      -- icon shadows tonally consistent on tinted panels instead of
      -- collapsing to a near-black halo.
      local bg = bgFromShadowColor(sc)
      local extended = {}
      for i = 1, math.max(sv, #colorList) do extended[i] = colorList[i] end
      extended[sv] = shadowColor(colorList[1], bg)
      colorList = extended
    end
    return _baseDrawImageAsPixels(matrix, x, y, colorList, nil)
  end

  function self.startup()
    -- Publish ourselves so other extensions can detect "PixelFont is
    -- loaded" and use the `false`-shadowcolor opt-out sentinel safely:
    --   Drawing.drawText(x, y, t, color, _G.PixelFont and false)
    -- evaluates to `false` when we're loaded (PixelFont's wrappers honor
    -- it) and `nil` when we aren't (native treats nil as no-shadow).
    _G.PixelFont = self

    -- Text override (immediate; no conflict with other extensions).
    self.oldDrawText = Drawing.drawText
    Drawing.drawText = self.drawText
    -- Patch Constants.Char widths so Utils.calcWordPixelLength matches
    -- what we actually render (avoids misaligned overdraws like the
    -- yellow evo-level highlight).
    self._savedCharWidths = {}
    for c, w in pairs(self.FontWidths) do
      if Constants.Char[c] then
        self._savedCharWidths[c] = Constants.Char[c].width
        Constants.Char[c].width = w
      end
    end
    -- drawMovesArea wrap. Used for two distinct fixes:
    --   1. Move-name spacing: when icon shadows widen PHYSICAL/SPECIAL by
    --      a column, shift the move name's drawText by +1 so it doesn't
    --      butt up against the icon's shadow.
    --   2. Header strip BG override: when HEADER_BG is set, replace the
    --      shadowcolor on drawText calls at headerY (y=81) with one
    --      derived from the actual visible BG, so PixelFont's midpoint
    --      formula tints toward that color instead of the theme's
    --      "Main background" assumption.
    if TrackerScreen and TrackerScreen.drawMovesArea then
      self._oldDrawMovesArea = TrackerScreen.drawMovesArea
      TrackerScreen.drawMovesArea = function(...)
        local shiftIcons = iconShadowsEnabled() and Options and Options["Show physical special icons"]
        local headerBgShadow = HEADER_BG and Utils and Utils.calcShadowColor and Utils.calcShadowColor(HEADER_BG) or nil
        if not shiftIcons and not headerBgShadow then
          return self._oldDrawMovesArea(...)
        end
        local targetX
        if shiftIcons then
          local moveNameOffset = 6 + 8
          if Theme and not Theme.MOVE_TYPES_ENABLED then
            moveNameOffset = moveNameOffset + 5
          end
          targetX = Constants.SCREEN.WIDTH + moveNameOffset
        end
        local origDrawText = Drawing.drawText
        Drawing.drawText = function(x, y, text, color, shadowcolor, ...)
          if targetX and x == targetX then x = x + 1 end
          if headerBgShadow and y == 81 then shadowcolor = headerBgShadow end
          return origDrawText(x, y, text, color, shadowcolor, ...)
        end
        local ok, err = pcall(self._oldDrawMovesArea, ...)
        Drawing.drawText = origDrawText
        if not ok then error(err) end
      end
    end
    -- nextMoveSpacing fix: Utils.getMovesLearnedHeader returns the
    -- spacing of the highlighted level overdraw as
    -- `calcWordPixelLength(prefix)` (Utils.lua:622). Two issues for our
    -- pixel font:
    --   1. Other callsites use `1 + calcWordPixelLength(...)` (compare
    --      TrackerScreen.lua:1191); this one's missing the +1.
    --   2. calcWordPixelLength reads Constants.Char widths, which we
    --      patch to match FontWidths in startup — but that patch can
    --      drift across reloads or be reset by other extensions, leaving
    --      the +1 fix over- or under-shifted by one column for chars
    --      whose widths differ (e.g. "/" is native=4, ours=3).
    -- Recompute directly from FontWidths so the overdraw position is
    -- always exactly where our renderer places the white prefix's last
    -- char, independent of Constants.Char state.
    if Utils and Utils.getMovesLearnedHeader then
      self._oldGetMovesLearnedHeader = Utils.getMovesLearnedHeader
      Utils.getMovesLearnedHeader = function(...)
        local header, lvl, sp = self._oldGetMovesLearnedHeader(...)
        if sp and header then
          local prefix = header:match("^(.-%()")
          if prefix then
            local total = 0
            for c in tostring(prefix):gmatch(utf8.charpattern) do
              total = total + (self.FontWidths[c] or 1) + 1
            end
            sp = total
          end
        end
        return header, lvl, sp
      end
    end
    -- Icon overrides: mutate Constants.PixelImages with shadowed copies.
    -- Gated by Options toggle so users can disable without restart.
    if iconShadowsEnabled() then
      for name, entry in pairs(self.ShadowedIcons) do
        local origEntry = pristine("Constants.PixelImages." .. name,
                                   Constants.PixelImages[name])
        if origEntry then
          Constants.PixelImages[name] = makeShadowed(
            origEntry, entry.matrix, entry.shadow_value)
        end
      end
      -- RogueMon-extension-local matrices: expose via shared registry so
      -- consuming files can opt in (e.g. POKEDOLLAR_GLYPH).
      if _G.Roguemon then
        _G.Roguemon.ShadowedIcons = _G.Roguemon.ShadowedIcons or {}
        for name, entry in pairs(self.ExternalShadowedIcons) do
          _G.Roguemon.ShadowedIcons[name] = makeShadowed(
            {}, entry.matrix, entry.shadow_value)
        end
      end
    end
  end

  function self.afterRedraw()
    -- Defer Drawing.drawImageAsPixels wrap to first frame, AFTER all other
    -- extensions have completed startup. Lua's pairs() iteration over
    -- CustomCode.ExtensionLibrary is non-deterministic, so we can't predict
    -- whether RoguemonExpansion's RLE override (which directly assigns
    -- Drawing.drawImageAsPixels in startup()) runs before or after us. Wrap
    -- here and we always sit on top of whatever the final version is.
    if not _wrapInstalled and iconShadowsEnabled() then
      _baseDrawImageAsPixels = pristine("Drawing.drawImageAsPixels",
                                        Drawing.drawImageAsPixels)
      Drawing.drawImageAsPixels = shadowDrawImageAsPixels
      _wrapInstalled = true
    end
  end

  function self.unload()
    if _G.PixelFont == self then _G.PixelFont = nil end
    Drawing.drawText = self.oldDrawText
    if self._savedCharWidths then
      for c, w in pairs(self._savedCharWidths) do
        if Constants.Char[c] then Constants.Char[c].width = w end
      end
      self._savedCharWidths = nil
    end
    if self._oldGetMovesLearnedHeader and Utils then
      Utils.getMovesLearnedHeader = self._oldGetMovesLearnedHeader
      self._oldGetMovesLearnedHeader = nil
    end
    if self._oldDrawMovesArea and TrackerScreen then
      TrackerScreen.drawMovesArea = self._oldDrawMovesArea
      self._oldDrawMovesArea = nil
    end
    if _baseDrawImageAsPixels then
      Drawing.drawImageAsPixels = _baseDrawImageAsPixels
    end
    local cache = _G.__roguemonCoreOriginals
    if cache then
      for name in pairs(self.ShadowedIcons) do
        local orig = cache["Constants.PixelImages." .. name]
        if orig then Constants.PixelImages[name] = orig end
      end
    end
  end

  return self
end

return PixelFont
